                <div style="text-align:right;padding-top:12px;font-weight:700;font-size:1rem;border-top:1px solid var(--border-color);margin-top:8px;color:var(--danger);">
                    Toplam: ${toplamGider.toLocaleString('tr-TR')} ₺
                </div>
